                              "DD MMM YYYY, hh:mm A",
                            )}
                          </small>
                          <small>
                            <span className="fw-semibold text-muted">
                              Updated:
                            </span>{" "}
                            {dayjs(role.updatedAt).format(
                              "DD MMM YYYY, hh:mm A",
